import{initializeApp}from"https://www.gstatic.com/firebasejs/12.10.0/firebase-app.js";import{getFirestore,collection,addDoc,getDocs,getDoc,doc,setDoc,updateDoc,deleteDoc}from"https://www.gstatic.com/firebasejs/12.10.0/firebase-firestore.js";export class Firebase{constructor(t){this.app=initializeApp(t),this.db=getFirestore(this.app)}async create(t,e){return await addDoc(collection(this.db,t),e)}async all(t){const e=await getDocs(collection(this.db,t)),a=[];return e.forEach(t=>{a.push({id:t.id,...t.data()})}),a}async read(t,e){const a=await getDoc(doc(this.db,t,e));return{id:a.id,...a.data()}}async update(t,e,a,i=!1){const s=doc(this.db,t,e);return i?await setDoc(s,a):await updateDoc(s,a)}async delete(t,e){return await deleteDoc(doc(this.db,t,e))}}